import{_ as s,c as o,o as i,a as e,b as a}from"./app.426dd711.js";const v=JSON.parse('{"title":"4. Dise\xF1o Simple (Simple Design)","description":"","frontmatter":{},"headers":[],"relativePath":"practices/simple-design.md"}'),n={name:"practices/simple-design.md"},l=e("h1",{id:"_4-diseno-simple-simple-design",tabindex:"-1"},[a("4. Dise\xF1o Simple "),e("em",null,"(Simple Design)"),a(),e("a",{class:"header-anchor",href:"#_4-diseno-simple-simple-design","aria-hidden":"true"},"#")],-1),r=e("blockquote",null,[e("p",null,"Esta pr\xE1ctica, deriva de un famoso principio t\xE9cnico del desarrollo de software: KISS. Cuyas siglas derivan del ingl\xE9s \u201CKeep it simple, stupid!\u201D -\xA1Mant\xE9nlo simple, est\xFApido!-. Dado que frecuentemente puede resultar \u201Cchocante\u201D el t\xE9rmino \u201Cstupid\u201D, a lo largo de los a\xF1os, se han ido produciendo variantes, como \u201Csilly\u201D -tonto-. B\xE1sicamente, con el principio KISS, se trata de mantener un dise\xF1o sencillo, estandarizado, de f\xE1cil compresi\xF3n y refactorizaci\xF3n.")],-1),t=e("p",null,"Las actividades que no crean valor no sirven y deben ser eliminadas. Por ejemplo: Tareas que no fueron solicitadas por el usuario, sobre-documentaci\xF3n del proyecto, etc. Como los requerimientos cambian, o pueden hacerlo, diariamente, hay que utilizar los dise\xF1os m\xE1s simples posibles para cumplir los requerimientos que tenemos en la actualidad. El desarrollo de software de calidad siempre se basa en un buen dise\xF1o. Por ello el dise\xF1o es la base para el buen funcionamiento del equipo.",-1),d=e("p",null,"Un dise\xF1o correcto en todo momento es aquel que cumple los siguientes requisitos reflejados en el programa resultante: ejecuta correctamente todo el dise\xF1o de pruebas; el programa funciona correctamente y muestra los resultados esperados; no contiene c\xF3digo redundante y aprovecha al m\xE1ximo las capacidades de la maquina; y la idea es que el programa final sea la forma mas simple de aglutinar todos los requerimientos. Puede resumirse en \u201Chacer lo m\xEDnimo indispensable, tan legible como sea posible\u201D.",-1),c=e("blockquote",null,[e("p",null,"Otros principios relacionados a la simplicidad son: YAGNI \u201C You aren\u2019t gonna need it\u201D (No lo vas a necesitar). No hagas nada que creas que en el futuro puede ser \xFAtil porque probablemente no lo vas a necesitar. Es una perdida de tiempo. OAOO \u201COnce and only once\u201D (Una \xFAnica vez). Las cosas se hacen una sola vez. El usuario siempre est\xE1 en mente. Se han de satisfacer sus necesidades pero nada m\xE1s.")],-1),p=[l,r,t,d,c];function u(m,_,h,f,g,q){return i(),o("div",null,p)}const y=s(n,[["render",u]]);export{v as __pageData,y as default};
